import React, { Fragment, useState } from "react";
import axios from "axios";
import Layout from "./Layout";

const Documents = () => {
  const [hospitalLicense, setHospitalLicense] = useState(null);
  const [registrationCertificate, setRegistrationCertificate] = useState(null);
  const [proofOfOwnership, setProofOfOwnership] = useState(null);
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");

  const handleFileChange = (e, setter) => {
    setter(e.target.files[0]);
  };

  const handleUpload = async (e) => {
    e.preventDefault();
    setMessage("");
    setError("");

    const formData = new FormData();
    const loggedInUserId = JSON.parse(localStorage.getItem("jwt")).user._id;
    formData.append("loggedInUserId", loggedInUserId);

    if (hospitalLicense) {
      formData.append("hospitalLicense", hospitalLicense);
    }
    if (registrationCertificate) {
      formData.append("registrationCertificate", registrationCertificate);
    }
    if (proofOfOwnership) {
      formData.append("proofOfOwnership", proofOfOwnership);
    }

    try {
      const response = await axios.post(
        `${process.env.REACT_APP_API_URL}/api/user/upload-documents`,
        formData,
        {
          headers: {
            "Content-Type": "multipart/form-data",
          },
        }
      );
      setMessage(response.data.message);
    } catch (err) {
      setError(err.response?.data?.error || "An error occurred during upload.");
    }
  };

  return (
    <Layout>
      <Fragment>
        <div className="flex flex-col w-full my-4 md:my-0 md:w-9/12 order-2 md:order-1">
          <div className="shadow-lg p-4 flex flex-col w-full mt-2">
            <h1 className="text-2xl font-semibold mb-4">Upload Documents</h1>
            {message && <div className="bg-green-200 px-4 py-2 rounded">{message}</div>}
            {error && <div className="bg-red-200 px-4 py-2 rounded">{error}</div>}
            <form onSubmit={handleUpload} className="flex flex-col space-y-4">
              <div>
                <label htmlFor="hospitalLicense" className="block text-lg font-medium text-gray-700">Hospital License</label>
                <input
                  type="file"
                  id="hospitalLicense"
                  name="hospitalLicense"
                  onChange={(e) => handleFileChange(e, setHospitalLicense)}
                  className="mt-1 block w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-blue-50 file:text-blue-700 hover:file:bg-blue-100"
                />
              </div>
              <div>
                <label htmlFor="registrationCertificate" className="block text-lg font-medium text-gray-700">Registration Certificate</label>
                <input
                  type="file"
                  id="registrationCertificate"
                  name="registrationCertificate"
                  onChange={(e) => handleFileChange(e, setRegistrationCertificate)}
                  className="mt-1 block w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-blue-50 file:text-blue-700 hover:file:bg-blue-100"
                />
              </div>
              <div>
                <label htmlFor="proofOfOwnership" className="block text-lg font-medium text-gray-700">Proof of Ownership</label>
                <input
                  type="file"
                  id="proofOfOwnership"
                  name="proofOfOwnership"
                  onChange={(e) => handleFileChange(e, setProofOfOwnership)}
                  className="mt-1 block w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-blue-50 file:text-blue-700 hover:file:bg-blue-100"
                />
              </div>
              <button
                type="submit"
                className="w-full text-center cursor-pointer px-4 py-2 text-gray-100"
                style={{ background: "#303031" }}
              >
                Upload Documents
              </button>
            </form>
          </div>
        </div>
      </Fragment>
    </Layout>
  );
};

export default Documents;
